#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        long long *a = (long long*)malloc(n*sizeof(long long));
        for(int i=0;i<n;i++) scanf("%lld", &a[i]);
        int maxSwaps = n-1;
        int (*swaps)[2] = malloc(maxSwaps * 2 * sizeof(int));
        int m = 0;
        for(int i=0;i<n-1;i++){
            int pos = i;
            for(int j=i+1;j<n;j++) if(a[j] < a[pos]) pos = j;
            if(pos!=i){
                long long tmp = a[i]; a[i]=a[pos]; a[pos]=tmp;
                swaps[m][0]=i; swaps[m][1]=pos; m++;
            }
        }
        printf("%d\n", m);
        for(int i=0;i<m;i++) printf("%d %d\n", swaps[i][0], swaps[i][1]);
        free(a); free(swaps);
    }
    return 0;
}

