import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        ops = []
        for i in range(n-1):
            pos = i
            for j in range(i+1, n):
                if a[j] < a[pos]:
                    pos = j
            if pos != i:
                a[i], a[pos] = a[pos], a[i]
                ops.append((i, pos))
        out_lines.append(str(len(ops)))
        out_lines.extend(f"{i} {j}" for i, j in ops)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

